class User_Files_Upload_Plugin {
    private $upload_subdir = 'user-files';

    public function __construct() {
        add_action('init', array($this, 'register_shortcodes'));
        add_action('admin_post_user_files_upload', array($this, 'handle_upload'));
        add_action('admin_post_nopriv_user_files_upload', array($this, 'handle_upload'));
    }

    public function register_shortcodes() {
        add_shortcode('user_files_upload_form', array($this, 'render_upload_form'));
    }

    public function render_upload_form() {
        if (!is_user_logged_in()) {
            return '<p>You must be logged in to upload files.</p>';
        }

        $action_url = esc_url(admin_url('admin-post.php'));
        $user_id = get_current_user_id();

        ob_start();
        ?>
        <form method="post" action="<?php echo $action_url; ?>" enctype="multipart/form-data">
            <p>
                <label for="user_file">Select file:</label><br>
                <input type="file" name="user_file" id="user_file" accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.txt,.xls,.xlsx,.ppt,.pptx">
            </p>
            <input type="hidden" name="action" value="user_files_upload">
            <input type="hidden" name="user_id" value="<?php echo esc_attr($user_id); ?>">
            <?php wp_nonce_field('user_files_upload_action', 'user_files_upload_nonce'); ?>
            <p><input type="submit" value="Upload File"></p>
        </form>
        <?php
        return ob_get_clean();
    }

    public function handle_upload() {
        if (!is_user_logged_in()) {
            wp_die('You must be logged in to upload files.');
        }

        if (
            !isset($_POST['user_files_upload_nonce']) ||
            !wp_verify_nonce($_POST['user_files_upload_nonce'], 'user_files_upload_action')
        ) {
            wp_die('Security check failed.');
        }

        if (empty($_FILES['user_file']) || !isset($_FILES['user_file']['name'])) {
            wp_die('No file uploaded.');
        }

        $file = $_FILES['user_file'];

        if (!empty($file['error'])) {
            wp_die('Upload error code: ' . intval($file['error']));
        }

        $allowed_mimes = array(
            'jpg|jpeg|jpe' => 'image/jpeg',
            'png'           => 'image/png',
            'gif'           => 'image/gif',
            'pdf'           => 'application/pdf',
            'doc'           => 'application/msword',
            'docx'          => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            'txt'           => 'text/plain',
            'xls'           => 'application/vnd.ms-excel',
            'xlsx'          => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            'ppt'           => 'application/vnd.ms-powerpoint',
            'pptx'          => 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        );

        $overrides = array(
            'test_form' => false,
            'mimes'     => $allowed_mimes,
        );

        require_once ABSPATH . 'wp-admin/includes/file.php';

        $uploaded = wp_handle_upload($file, $overrides);

        if (isset($uploaded['error'])) {
            wp_die('Upload failed: ' . esc_html($uploaded['error']));
        }

        $upload_dir = wp_upload_dir();
        $target_dir = trailingslashit($upload_dir['basedir']) . $this->upload_subdir;

        if (!file_exists($target_dir)) {
            wp_mkdir_p($target_dir);
        }

        $filename = wp_unique_filename($target_dir, basename($uploaded['file']));
        $new_file_path = trailingslashit($target_dir) . $filename;

        if (!rename($uploaded['file'], $new_file_path)) {
            wp_die('Could not move uploaded file.');
        }

        $file_url = trailingslashit($upload_dir['baseurl']) . $this->upload_subdir . '/' . $filename;

        $attachment = array(
            'post_mime_type' => $uploaded['type'],
            'post_title'     => sanitize_file_name(pathinfo($filename, PATHINFO_FILENAME)),
            'post_content'   => '',
            'post_status'    => 'inherit',
        );

        $attachment_id = wp_insert_attachment($attachment, $new_file_path);

        if (!is_wp_error($attachment_id)) {
            require_once ABSPATH . 'wp-admin/includes/image.php';
            $attach_data = wp_generate_attachment_metadata($attachment_id, $new_file_path);
            wp_update_attachment_metadata($attachment_id, $attach_data);
            update_post_meta($attachment_id, '_user_uploaded_file', 1);
            update_post_meta($attachment_id, '_uploaded_by_user', get_current_user_id());
        }

        wp_safe_redirect(add_query_arg(array('uploaded' => '1', 'file' => rawurlencode($filename)), wp_get_referer() ? wp_get_referer() : home_url('/')));
        exit;
    }
}

new User_Files_Upload_Plugin();